+    let bytesRead = 0;
+    while (pos + bytesRead < data.length) {
+        const b = data[pos + bytesRead];
+        bytesRead++;
+        value |= (b & 0x7F) << shift;
+        if ((b & 0x80) === 0) break;
+        shift += 7;
+    }
+    return { value, bytesRead };
