+            while (pos < pageEnd) {
+                const { value: pageTag, bytesRead: pTagBytes } = readVarintAt(metaBytes, pos);
+                pos += pTagBytes;
+                const pFieldNum = pageTag >> 3;
+                const pWireType = pageTag & 0x7;
