+                    // length (varint)
+                    const { value, bytesRead } = readVarintAt(metaBytes, pos);
+                    pos += bytesRead;
+                    length = value;
+                } else if (pWireType === 0) {
+                    const { bytesRead } = readVarintAt(metaBytes, pos);
+                    pos += bytesRead;
+                } else if (pWireType === 2) {
