+async function loadWasm() {
+    if (wasm) return wasm;
+    try {
+        const url = new URL('./lanceql.wasm', import.meta.url);
+        url.searchParams.set('v', Date.now().toString());
+        const response = await fetch(url);
+        const bytes = await response.arrayBuffer();
