+    const { id, method, args } = data;
+
+    try {
+        let result;
+
+        // Store operations
+        if (method === 'ping') {
+            result = 'pong';
+        } else if (method === 'open') {
+            await getStore(args.name, args.options, args.encryption);
+            result = true;
+        } else if (method === 'get') {
+            result = await (await getStore(args.name)).get(args.key);
+        } else if (method === 'set') {
+            await (await getStore(args.name)).set(args.key, args.value);
