+// Vault singleton
+let vaultInstance = null;
+
+async function getVault(encryptionConfig = null) {
+    if (!vaultInstance) {
+        vaultInstance = new WorkerVault();
+    }
+    // Re-open with encryption if not already done
+    await vaultInstance.open(encryptionConfig);
